import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  nameAr: string;
  nameEn: string;
  price: number;
  imageUrl: string;
  brand: string;
  size: string;
  isSubscriptionAvailable: boolean;
  sodiumLevel: number; // mg/L
  phLevel: number;
}

export interface CartItem extends Product {
  quantity: number;
  isSubscribed: boolean;
}

export interface TimeSlot {
  id: string;
  label: string;
  range: string;
}

export enum StockPreference {
  CALL_ME = 'call_me',
  REPLACE = 'replace',
  CANCEL = 'cancel',
}

export enum Tab {
  HOME = 'home',
  CART = 'cart',
  PROFILE = 'profile',
}

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { CartItem, Product } from '../types';

interface CartContextType {
  items: CartItem[];
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  updateQuantity: (productId: string, delta: number) => void;
  toggleSubscription: (productId: string) => void;
  clearCart: () => void;
  subtotal: number;
}

const CartContext = createContext<CartContextType | undefined>(undefined);

export const CartProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [items, setItems] = useState<CartItem[]>([]);

  const addToCart = (product: Product) => {
    setItems((prev) => {
      const existing = prev.find((i) => i.id === product.id);
      if (existing) {
        return prev.map((i) =>
          i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i
        );
      }
      return [...prev, { ...product, quantity: 1, isSubscribed: false }];
    });
  };

  const removeFromCart = (productId: string) => {
    setItems((prev) => prev.filter((i) => i.id !== productId));
  };

  const updateQuantity = (productId: string, delta: number) => {
    setItems((prev) => {
      return prev.map((item) => {
        if (item.id === productId) {
          const newQuantity = Math.max(0, item.quantity + delta);
          return { ...item, quantity: newQuantity };
        }
        return item;
      }).filter(item => item.quantity > 0);
    });
  };

  const toggleSubscription = (productId: string) => {
    setItems((prev) =>
      prev.map((item) =>
        item.id === productId ? { ...item, isSubscribed: !item.isSubscribed } : item
      )
    );
  };

  const clearCart = () => setItems([]);

  const subtotal = items.reduce((sum, item) => {
    const price = item.isSubscribed ? item.price * 0.9 : item.price; // 10% off if subscribed
    return sum + price * item.quantity;
  }, 0);

  return (
    <CartContext.Provider
      value={{ items, addToCart, removeFromCart, updateQuantity, toggleSubscription, clearCart, subtotal }}
    >
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) throw new Error('useCart must be used within a CartProvider');
  return context;
};

import React from 'react';
import { Product } from '../types';
import { useCart } from '../store/CartContext';
import { Plus, Minus, RefreshCw, Info } from 'lucide-react';

interface ProductCardProps {
  product: Product;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const { items, addToCart, updateQuantity, toggleSubscription } = useCart();
  const cartItem = items.find((i) => i.id === product.id);
  const quantity = cartItem?.quantity || 0;
  const isSubscribed = cartItem?.isSubscribed || false;

  const handleAdd = (e: React.MouseEvent) => {
    e.stopPropagation();
    addToCart(product);
  };

  const handleIncrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    updateQuantity(product.id, 1);
  };

  const handleDecrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    updateQuantity(product.id, -1);
  };

  const handleSubscribeToggle = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (quantity > 0) {
      toggleSubscription(product.id);
    } else {
        // Auto add if toggling subscription on empty item
        addToCart(product);
        setTimeout(() => toggleSubscription(product.id), 0);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full relative group">
      {/* Badges */}
      <div className="absolute top-2 right-2 flex flex-col gap-1 z-10">
        {product.sodiumLevel < 15 && (
            <span className="bg-green-100 text-green-700 text-[10px] px-2 py-1 rounded-full font-bold">
            صوديوم منخفض
            </span>
        )}
        {isSubscribed && (
            <span className="bg-secondary text-white text-[10px] px-2 py-1 rounded-full font-bold shadow-md animate-pulse">
            اشتراك مفعل
            </span>
        )}
      </div>

      {/* Image Area */}
      <div className="h-40 bg-gray-50 relative flex items-center justify-center p-4">
        <img
          src={product.imageUrl}
          alt={product.nameEn}
          className="max-h-full max-w-full object-contain mix-blend-multiply"
        />
      </div>

      {/* Content Area */}
      <div className="p-3 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <div>
            <h3 className="font-bold text-gray-800 text-base leading-tight">{product.nameAr}</h3>
            <p className="text-gray-400 text-xs font-sans mt-0.5">{product.nameEn}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 text-xs text-gray-500 mb-2">
            <span className="bg-gray-100 px-1.5 py-0.5 rounded text-gray-600">{product.size}</span>
            <span>pH {product.phLevel}</span>
        </div>

        <div className="mt-auto">
            <div className="flex items-center justify-between mb-3">
                <div className="flex flex-col">
                    <span className="font-bold text-primary text-lg">
                        {isSubscribed ? (product.price * 0.9).toFixed(2) : product.price.toFixed(2)}
                        <span className="text-xs text-gray-500 mr-1 font-normal">ر.س</span>
                    </span>
                     {isSubscribed && <span className="text-[10px] text-gray-400 line-through">{product.price.toFixed(2)}</span>}
                </div>
            </div>

            {/* Quick Actions */}
            <div className="flex items-center justify-between gap-2">
                {quantity === 0 ? (
                    <button
                        onClick={handleAdd}
                        className="w-full bg-primary text-white py-2 rounded-lg font-bold text-sm shadow-md active:scale-95 transition-transform flex items-center justify-center gap-2"
                    >
                        <Plus size={16} />
                        <span>أضف للسلة</span>
                    </button>
                ) : (
                    <div className="flex items-center bg-gray-100 rounded-lg w-full justify-between p-1">
                        <button onClick={handleIncrement} className="w-8 h-8 bg-white rounded shadow-sm text-primary flex items-center justify-center active:scale-95">
                            <Plus size={16} />
                        </button>
                        <span className="font-bold text-gray-800 text-sm mx-2">{quantity}</span>
                        <button onClick={handleDecrement} className="w-8 h-8 bg-white rounded shadow-sm text-gray-500 flex items-center justify-center active:scale-95">
                            <Minus size={16} />
                        </button>
                    </div>
                )}
            </div>

            {/* Subscription Toggle */}
            {product.isSubscriptionAvailable && (
                 <button
                    onClick={handleSubscribeToggle}
                    className={`w-full mt-2 py-1.5 px-2 rounded border border-dashed flex items-center justify-center gap-1.5 text-xs transition-colors ${
                        isSubscribed
                        ? 'border-secondary text-secondary bg-pink-50'
                        : 'border-gray-300 text-gray-500 hover:bg-gray-50'
                    }`}
                 >
                    <RefreshCw size={12} className={isSubscribed ? 'animate-spin-slow' : ''} />
                    <span>{isSubscribed ? 'إلغاء الاشتراك' : 'اشترك ووفر 10%'}</span>
                 </button>
            )}
        </div>
      </div>
    </div>
  );
};

