        <div className="flex flex-col gap-2">
            {[
                { val: StockPreference.CALL_ME, label: 'اتصل بي' },
                { val: StockPreference.REPLACE, label: 'استبدل بمنتج مشابه' },
                { val: StockPreference.CANCEL, label: 'إلغاء المنتج' },
            ].map((opt) => (
                <label key={opt.val} className="flex items-center gap-3 p-2 rounded-lg hover:bg-gray-50 cursor-pointer">
                    <input 
                        type="radio" 
                        name="stock_pref" 
                        checked={stockPref === opt.val}
                        onChange={() => setStockPref(opt.val)}
                        className="w-4 h-4 text-primary focus:ring-primary"
                    />
                    <span className="text-sm text-gray-700">{opt.label}</span>
                </label>
