                <input type="checkbox" checked={recycling} onChange={(e) => setRecycling(e.target.checked)} className="sr-only peer" />
                <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-green-600"></div>
            </label>
       </div>

      {/* Payment Summary */}
      <div className="bg-white p-6 rounded-t-[2rem] shadow-[0_-4px_20px_rgba(0,0,0,0.05)] fixed bottom-0 left-0 right-0 z-20">
        <div className="space-y-2 mb-4 text-sm">
            <div className="flex justify-between text-gray-500">
                <span>المجموع الفرعي</span>
                <span>{subtotal.toFixed(2)} ر.س</span>
            </div>
            <div className="flex justify-between text-gray-500">
                <span>ضريبة القيمة المضافة (15%)</span>
                <span>{vatAmount.toFixed(2)} ر.س</span>
            </div>
            <div className="flex justify-between text-gray-500">
                <span>رسوم التوصيل</span>
                <span>{DELIVERY_FEE.toFixed(2)} ر.س</span>
            </div>
            <div className="border-t border-dashed border-gray-300 my-2"></div>
            <div className="flex justify-between font-bold text-lg text-gray-900">
                <span>الإجمالي</span>
                <span>{total.toFixed(2)} ر.س</span>
