};

import React from 'react';
import { Home, ShoppingCart, User } from 'lucide-react';
import { Tab } from '../types';
import { useCart } from '../store/CartContext';

interface BottomNavProps {
  currentTab: Tab;
  onTabChange: (tab: Tab) => void;
}

export const BottomNav: React.FC<BottomNavProps> = ({ currentTab, onTabChange }) => {
  const { items } = useCart();
  const itemCount = items.reduce((acc, item) => acc + item.quantity, 0);

  const tabs = [
    { id: Tab.HOME, icon: Home, label: 'الرئيسية' },
    { id: Tab.CART, icon: ShoppingCart, label: 'السلة', badge: itemCount },
    { id: Tab.PROFILE, icon: User, label: 'حسابي' },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 pb-safe px-6 py-2 flex justify-between items-center z-50">
      {tabs.map((tab) => {
        const isActive = currentTab === tab.id;
        return (
          <button
            key={tab.id}
            onClick={() => onTabChange(tab.id)}
            className={`flex flex-col items-center justify-center w-16 h-14 relative transition-colors ${
              isActive ? 'text-primary' : 'text-gray-400'
            }`}
          >
            <div className={`relative p-1 rounded-xl transition-all ${isActive ? 'bg-blue-50 -translate-y-1' : ''}`}>
                <tab.icon size={24} className={isActive ? 'fill-current' : ''} />
                {tab.badge !== undefined && tab.badge > 0 && (
                <span className="absolute -top-1 -right-1 bg-secondary text-white text-[10px] font-bold w-4 h-4 rounded-full flex items-center justify-center border border-white">
                    {tab.badge}
                </span>
                )}
            </div>
            <span className={`text-[10px] font-medium mt-1 ${isActive ? 'font-bold' : ''}`}>{tab.label}</span>
          </button>
        );
      })}
    </div>
  );
};

import React, { useState } from 'react';
import { CartProvider } from './store/CartContext';
import { Home } from './pages/Home';
import { Checkout } from './pages/Checkout';
import { Profile } from './pages/Profile';
import { BottomNav } from './components/BottomNav';
import { Tab } from './types';

const App: React.FC = () => {
  const [currentTab, setCurrentTab] = useState<Tab>(Tab.HOME);

  const renderContent = () => {
    switch (currentTab) {
      case Tab.HOME:
        return <Home />;
      case Tab.CART:
        return <Checkout />;
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Home />;
    }
  };

  return (
    <CartProvider>
      <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
        {/* Main Content Area */}
        <main className="h-full overflow-y-auto no-scrollbar">
            {renderContent()}
        </main>

        {/* Bottom Navigation */}
        <BottomNav currentTab={currentTab} onTabChange={setCurrentTab} />
      </div>
    </CartProvider>
  );
};

export default App;

