import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  login: (email: string, pass: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  logout: () => void;
  error: string | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// Mock Data
const MOCK_USER: User = {
  id: 'u_123',
  name: 'عبدالله محمد',
  email: 'test@wadi.com',
  phone: '0551234567',
  avatarUrl: 'https://i.pravatar.cc/150?u=a042581f4e29026704d',
};

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Simulate checking local storage for persisted session
    const stored = localStorage.getItem('wadi_user');
    if (stored) {
      setUser(JSON.parse(stored));
    }
    setIsLoading(false);
  }, []);

  const login = async (email: string, pass: string) => {
    setIsLoading(true);
    setError(null);
    // Simulate API call
    setTimeout(() => {
      if (email === 'test@wadi.com' && pass === '123456') {
        const u = MOCK_USER;
        setUser(u);
        localStorage.setItem('wadi_user', JSON.stringify(u));
        setIsLoading(false);
      } else if (email && pass) {
         // Allow any other login for prototype purposes
         const u = { ...MOCK_USER, email, name: email.split('@')[0] };
         setUser(u);
         localStorage.setItem('wadi_user', JSON.stringify(u));
         setIsLoading(false);
      } else {
        setError('البريد الإلكتروني أو كلمة المرور غير صحيحة');
        setIsLoading(false);
      }
    }, 1500);
  };

  const register = async (name: string, email: string, pass: string) => {
    setIsLoading(true);
    setError(null);
    setTimeout(() => {
        const u = { ...MOCK_USER, name, email, id: `u_${Date.now()}` };
        setUser(u);
        localStorage.setItem('wadi_user', JSON.stringify(u));
        setIsLoading(false);
    }, 1500);
  };

  const loginWithGoogle = async () => {
    setIsLoading(true);
    setTimeout(() => {
        const u = { ...MOCK_USER, name: 'Google User', id: 'g_123' };
        setUser(u);
        localStorage.setItem('wadi_user', JSON.stringify(u));
        setIsLoading(false);
    }, 1000);
  }

  const logout = () => {
    setUser(null);
    localStorage.removeItem('wadi_user');
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, login, register, loginWithGoogle, logout, error }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

