  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');

  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-white text-primary">
        <Loader2 className="animate-spin" size={48} />
      </div>
    );
  }

  if (!user) {
    if (authMode === 'login') {
      return <Login onToggleMode={() => setAuthMode('register')} />;
    } else {
      return <Register onToggleMode={() => setAuthMode('login')} />;
    }
  }

  const renderContent = () => {
    switch (currentTab) {
      case Tab.HOME:
        return <Home />;
      case Tab.PROMOTIONS:
        return <Promotions />;
      case Tab.CART:
        return <Checkout />;
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Home />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
      <main className="h-full overflow-y-auto no-scrollbar">
          {renderContent()}
      </main>
      <BottomNav currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <CartProvider>
        <AppContent />
      </CartProvider>
    </AuthProvider>
  );
};

