                                    className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                                        selectedSizes.includes(size)
                                        ? 'bg-primary text-white border-primary'
                                        : 'bg-white border-gray-200 text-gray-600'
                                    }`}
                                >
                                    {size}
                                </button>
                            ))}
