import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  sendOtp: (phone: string) => Promise<void>;
  verifyOtp: (phone: string, code: string) => Promise<void>;
  logout: () => void;
  error: string | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Check local storage
    const stored = localStorage.getItem('wadi_user');
    if (stored) {
      setUser(JSON.parse(stored));
    }
    setIsLoading(false);
  }, []);

  const sendOtp = async (phone: string) => {
    setIsLoading(true);
    setError(null);
    // Simulate API call to send SMS
    return new Promise<void>((resolve) => {
        setTimeout(() => {
            setIsLoading(false);
            resolve();
        }, 1500);
    });
  };

  const verifyOtp = async (phone: string, code: string) => {
    setIsLoading(true);
    setError(null);
    return new Promise<void>((resolve, reject) => {
        setTimeout(() => {
            if (code === '1234') { // Mock OTP
                const u: User = {
                    id: `u_${phone}`,
                    name: 'عميل وادي', // Default name, could ask for it later
                    email: `${phone}@wadi.com`,
                    phone: phone,
                    avatarUrl: `https://ui-avatars.com/api/?name=${phone}&background=random`,
                };
                setUser(u);
                localStorage.setItem('wadi_user', JSON.stringify(u));
                setIsLoading(false);
                resolve();
            } else {
                setError('رمز التحقق غير صحيح');
                setIsLoading(false);
                reject();
            }
        }, 1500);
    });
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('wadi_user');
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, sendOtp, verifyOtp, logout, error }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

