import { Product } from '../types';
import { useCart } from '../store/CartContext';
import { ChevronRight, Share2, Heart, Plus, Minus, RefreshCw, Droplets, FlaskConical, Scaling, Tag, Check } from 'lucide-react';

interface ProductDetailsProps {
  product: Product;
  onBack: () => void;
}

export const ProductDetails: React.FC<ProductDetailsProps> = ({ product, onBack }) => {
  const { items, addToCart, updateQuantity, toggleSubscription } = useCart();
  const cartItem = items.find((i) => i.id === product.id);
  const quantity = cartItem?.quantity || 0;
  const isSubscribed = cartItem?.isSubscribed || false;

  const handleAdd = () => addToCart(product);
  const handleIncrement = () => updateQuantity(product.id, 1);
  const handleDecrement = () => updateQuantity(product.id, -1);

  const handleSubscribeToggle = () => {
    if (quantity > 0) {
      toggleSubscription(product.id);
    } else {
        addToCart(product);
        setTimeout(() => toggleSubscription(product.id), 0);
    }
  };

  return (
    <div className="bg-white min-h-screen pb-24 relative animate-slide-up">
      {/* Header */}
      <div className="absolute top-0 left-0 right-0 p-4 flex justify-between items-center z-10">
        <button onClick={onBack} className="w-10 h-10 bg-white/80 backdrop-blur rounded-full shadow-sm flex items-center justify-center text-gray-700 active:scale-95 transition-transform">
            <ChevronRight size={24} />
        </button>
        <div className="flex gap-2">
            <button className="w-10 h-10 bg-white/80 backdrop-blur rounded-full shadow-sm flex items-center justify-center text-gray-700 active:scale-95 transition-transform">
                <Share2 size={20} />
            </button>
            <button className="w-10 h-10 bg-white/80 backdrop-blur rounded-full shadow-sm flex items-center justify-center text-gray-700 active:scale-95 transition-transform">
                <Heart size={20} />
            </button>
        </div>
      </div>

      {/* Image */}
      <div className="h-[45vh] bg-gray-50 flex items-center justify-center p-8 pb-12">
        <img src={product.imageUrl} alt={product.nameEn} className="max-h-full max-w-full object-contain mix-blend-multiply" />
      </div>

      {/* Content */}
      <div className="px-6 py-6 -mt-8 bg-white rounded-t-[2.5rem] relative z-0 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] min-h-[60vh]">
         <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-8"></div>

         <div className="flex justify-between items-start mb-2">
            <div>
                <h1 className="text-2xl font-bold text-gray-900">{product.nameAr}</h1>
                <p className="text-gray-500 font-sans text-sm mt-1">{product.nameEn}</p>
            </div>
            <div className="flex flex-col items-end">
                 <span className="text-2xl font-bold text-primary">
                    {isSubscribed ? (product.price * 0.9).toFixed(2) : product.price.toFixed(2)} 
