         {/* Subscription Option */}
         {product.isSubscriptionAvailable && (
             <div 
                onClick={handleSubscribeToggle}
                className={`p-4 rounded-2xl border-2 cursor-pointer transition-all mb-8 flex items-center justify-between ${
