             >
                 <div className="flex items-center gap-3">
                     <div className={`w-12 h-12 rounded-full flex items-center justify-center shrink-0 ${isSubscribed ? 'bg-secondary text-white' : 'bg-gray-100 text-gray-400'}`}>
                         <RefreshCw size={24} className={isSubscribed ? 'animate-spin-slow' : ''} />
                     </div>
                     <div>
                         <p className={`font-bold text-sm ${isSubscribed ? 'text-secondary' : 'text-gray-900'}`}>
                             {isSubscribed ? 'اشتراكك مفعل' : 'اشترك ووفر 10%'}
                         </p>
                         <p className="text-xs text-gray-500 mt-0.5">توصيل دوري (أسبوعي / شهري) تلقائي</p>
                     </div>
                 </div>
                 <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 ${isSubscribed ? 'border-secondary bg-secondary' : 'border-gray-300'}`}>
                     {isSubscribed && <Check size={14} className="text-white" />}
                 </div>
             </div>
         )}

         {/* Description */}
         <div className="mb-8">
             <h3 className="font-bold text-lg mb-2 text-gray-800">عن المنتج</h3>
             <p className="text-gray-500 text-sm leading-relaxed text-justify">
                 مياه {product.nameAr} هي مياه جوفية طبيعية نقية، معبأة من مصادر محمية لضمان أعلى مستويات الجودة والنقاء. تتميز بتوازن مثالي في الأملاح والمعادن، مما يجعلها خيارك الأمثل للترطيب اليومي لك ولعائلتك. تأتي في عبوات صحية وآمنة، مثالية للمنازل والمكاتب والمساجد.
             </p>
         </div>
      </div>

      {/* Bottom Action Bar */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 p-4 px-6 z-20 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] max-w-md mx-auto">
        <div className="flex items-center gap-4">
             {/* Quantity Controls */}
             <div className="flex items-center bg-gray-100 rounded-xl px-2 py-3">
                <button 
                    onClick={handleDecrement}
                    disabled={quantity === 0}
                    className="w-8 h-8 bg-white rounded-lg shadow-sm text-gray-600 flex items-center justify-center active:scale-95 disabled:opacity-50 transition-transform"
                >
                    <Minus size={18} />
                </button>
                <span className="w-12 text-center font-bold text-lg">{quantity}</span>
                <button 
                    onClick={quantity === 0 ? handleAdd : handleIncrement}
                    className="w-8 h-8 bg-white rounded-lg shadow-sm text-primary flex items-center justify-center active:scale-95 transition-transform"
                >
                    <Plus size={18} />
                </button>
             </div>

             {/* Add Button */}
             <button 
                onClick={quantity === 0 ? handleAdd : onBack}
                className={`flex-1 text-white h-14 rounded-xl font-bold text-lg shadow-lg active:scale-[0.98] transition-all flex items-center justify-center gap-2 ${quantity > 0 ? 'bg-green-600 shadow-green-600/30' : 'bg-primary shadow-primary/30'}`}
             >
                 {quantity === 0 ? (
                     <>
                        <Plus size={20} />
                        أضف للسلة
                     </>
                 ) : (
                    <>
                        <Check size={20} />
                        إتمام التسوق
                    </>
                 )}
             </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Product } from '../types';
import { useCart } from '../store/CartContext';
import { Plus, Minus, RefreshCw, Info } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  onProductClick?: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product, onProductClick }) => {
  const { items, addToCart, updateQuantity, toggleSubscription } = useCart();
  const cartItem = items.find((i) => i.id === product.id);
  const quantity = cartItem?.quantity || 0;
  const isSubscribed = cartItem?.isSubscribed || false;

  const handleCardClick = () => {
    if (onProductClick) {
        onProductClick(product);
    }
  };

  const handleAdd = (e: React.MouseEvent) => {
    e.stopPropagation();
    addToCart(product);
  };

  const handleIncrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    updateQuantity(product.id, 1);
  };

  const handleDecrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    updateQuantity(product.id, -1);
  };

  const handleSubscribeToggle = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (quantity > 0) {
      toggleSubscription(product.id);
    } else {
        // Auto add if toggling subscription on empty item
        addToCart(product);
        setTimeout(() => toggleSubscription(product.id), 0);
    }
  };

  return (
    <div 
        onClick={handleCardClick}
        className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full relative group cursor-pointer active:scale-[0.99] transition-transform"
    >
      {/* Badges */}
      <div className="absolute top-2 right-2 flex flex-col gap-1 z-10">
        {product.sodiumLevel < 15 && (
            <span className="bg-green-100 text-green-700 text-[10px] px-2 py-1 rounded-full font-bold">
            صوديوم منخفض
            </span>
        )}
        {isSubscribed && (
            <span className="bg-secondary text-white text-[10px] px-2 py-1 rounded-full font-bold shadow-md animate-pulse">
            اشتراك مفعل
            </span>
        )}
      </div>

      {/* Image Area */}
      <div className="h-40 bg-gray-50 relative flex items-center justify-center p-4">
        <img
          src={product.imageUrl}
          alt={product.nameEn}
          className="max-h-full max-w-full object-contain mix-blend-multiply"
        />
      </div>

      {/* Content Area */}
      <div className="p-3 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <div>
            <h3 className="font-bold text-gray-800 text-base leading-tight">{product.nameAr}</h3>
            <p className="text-gray-400 text-xs font-sans mt-0.5">{product.nameEn}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 text-xs text-gray-500 mb-2">
            <span className="bg-gray-100 px-1.5 py-0.5 rounded text-gray-600">{product.size}</span>
            <span>pH {product.phLevel}</span>
        </div>

        <div className="mt-auto">
            <div className="flex items-center justify-between mb-3">
                <div className="flex flex-col">
                    <span className="font-bold text-primary text-lg">
                        {isSubscribed ? (product.price * 0.9).toFixed(2) : product.price.toFixed(2)}
                        <span className="text-xs text-gray-500 mr-1 font-normal">ر.س</span>
                    </span>
                     {isSubscribed && <span className="text-[10px] text-gray-400 line-through">{product.price.toFixed(2)}</span>}
                </div>
            </div>

            {/* Quick Actions */}
            <div className="flex items-center justify-between gap-2">
                {quantity === 0 ? (
                    <button
                        onClick={handleAdd}
                        className="w-full bg-primary text-white py-2 rounded-lg font-bold text-sm shadow-md active:scale-95 transition-transform flex items-center justify-center gap-2"
                    >
                        <Plus size={16} />
                        <span>أضف للسلة</span>
                    </button>
                ) : (
                    <div className="flex items-center bg-gray-100 rounded-lg w-full justify-between p-1">
                        <button onClick={handleIncrement} className="w-8 h-8 bg-white rounded shadow-sm text-primary flex items-center justify-center active:scale-95">
                            <Plus size={16} />
                        </button>
                        <span className="font-bold text-gray-800 text-sm mx-2">{quantity}</span>
                        <button onClick={handleDecrement} className="w-8 h-8 bg-white rounded shadow-sm text-gray-500 flex items-center justify-center active:scale-95">
                            <Minus size={16} />
                        </button>
                    </div>
                )}
            </div>

            {/* Subscription Toggle */}
            {product.isSubscriptionAvailable && (
                 <button
                    onClick={handleSubscribeToggle}
                    className={`w-full mt-2 py-1.5 px-2 rounded border border-dashed flex items-center justify-center gap-1.5 text-xs transition-colors ${
                        isSubscribed
                        ? 'border-secondary text-secondary bg-pink-50'
                        : 'border-gray-300 text-gray-500 hover:bg-gray-50'
                    }`}
                 >
                    <RefreshCw size={12} className={isSubscribed ? 'animate-spin-slow' : ''} />
                    <span>{isSubscribed ? 'إلغاء الاشتراك' : 'اشترك ووفر 10%'}</span>
                 </button>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { MapPin, Search, Filter, ChevronDown, SlidersHorizontal, X, ArrowUpDown, Check, Star, ShoppingCart } from 'lucide-react';
import { MOCK_PRODUCTS } from '../constants';
import { ProductCard } from '../components/ProductCard';
import { useCart } from '../store/CartContext';
import { Product } from '../types';

type SortOption = 'popular' | 'price_asc' | 'price_desc';
type PHLevel = 'all' | 'acidic' | 'neutral' | 'alkaline';

interface HomeProps {
  onGoToCart: () => void;
  onProductClick: (product: Product) => void;
}

export const Home: React.FC<HomeProps> = ({ onGoToCart, onProductClick }) => {
  const { items } = useCart();
  const cartCount = items.reduce((acc, item) => acc + item.quantity, 0);

  const [searchTerm, setSearchTerm] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  // Filter States
  const [activeQuickFilter, setActiveQuickFilter] = useState<string>('all');
  const [sortOption, setSortOption] = useState<SortOption>('popular');
  const [maxPrice, setMaxPrice] = useState<number>(50);
  const [selectedBrands, setSelectedBrands] = useState<string[]>([]);
  const [selectedSizes, setSelectedSizes] = useState<string[]>([]);
  const [lowSodiumOnly, setLowSodiumOnly] = useState(false);
  const [selectedPh, setSelectedPh] = useState<PHLevel>('all');

  // Derived Options
  const brands = useMemo(() => Array.from(new Set(MOCK_PRODUCTS.map(p => p.brand))), []);
  const sizes = useMemo(() => {
    // Extract unique sizes (e.g. 330ml, 550ml, 5L)
    const allSizes = MOCK_PRODUCTS.map(p => {
        const match = p.size.match(/^([\d\.]+[a-zA-Z]+)/);
        return match ? match[1] : '';
    }).filter(Boolean);
    return Array.from(new Set(allSizes));
  }, []);

  // Filter Logic
  const filteredProducts = useMemo(() => {
    let result = MOCK_PRODUCTS.filter((p) => {
      const matchesSearch = p.nameAr.includes(searchTerm) || p.nameEn.toLowerCase().includes(searchTerm.toLowerCase());

      // Quick Filters (Legacy support combined with new logic)
      let matchesQuick = true;
      if (activeQuickFilter === 'low-sodium') matchesQuick = p.sodiumLevel < 15;
      if (activeQuickFilter === 'donations') matchesQuick = p.nameAr.includes('مساجد') || p.price < 15;

      // Advanced Filters
      const matchesBrand = selectedBrands.length === 0 || selectedBrands.includes(p.brand);
      const matchesPrice = p.price <= maxPrice;
      const matchesSodium = !lowSodiumOnly || p.sodiumLevel < 15;

      // Size Logic (Simple substring match)
      const matchesSize = selectedSizes.length === 0 || selectedSizes.some(s => p.size.includes(s));

      // pH Logic
      let matchesPh = true;
      if (selectedPh === 'acidic') matchesPh = p.phLevel < 7;
      if (selectedPh === 'neutral') matchesPh = p.phLevel >= 7 && p.phLevel <= 7.5;
      if (selectedPh === 'alkaline') matchesPh = p.phLevel > 7.5;

      return matchesSearch && matchesQuick && matchesBrand && matchesPrice && matchesSodium && matchesSize && matchesPh;
    });

    // Sort Logic
    return result.sort((a, b) => {
      switch (sortOption) {
        case 'price_asc': return a.price - b.price;
        case 'price_desc': return b.price - a.price;
        case 'popular': default: return 0; // Maintain default order (mock popularity)
      }
    });
  }, [searchTerm, activeQuickFilter, selectedBrands, maxPrice, lowSodiumOnly, selectedSizes, selectedPh, sortOption]);

  const activeFiltersCount = [
    selectedBrands.length > 0,
    selectedSizes.length > 0,
    lowSodiumOnly,
    selectedPh !== 'all',
    maxPrice < 50
  ].filter(Boolean).length;

  const toggleBrand = (brand: string) => {
    setSelectedBrands(prev => prev.includes(brand) ? prev.filter(b => b !== brand) : [...prev, brand]);
  };

  const toggleSize = (size: string) => {
    setSelectedSizes(prev => prev.includes(size) ? prev.filter(s => s !== size) : [...prev, size]);
  };

  const resetFilters = () => {
    setSortOption('popular');
    setMaxPrice(50);
    setSelectedBrands([]);
    setSelectedSizes([]);
    setLowSodiumOnly(false);
    setSelectedPh('all');
    setActiveQuickFilter('all');
  };

  return (
    <div className={`pb-24 min-h-screen relative ${isFilterOpen ? 'overflow-hidden h-screen' : ''}`}>
      {/* Header Section */}
      <div className="bg-primary pt-12 pb-8 px-4 rounded-b-[2rem] shadow-xl relative z-10">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2 text-white">
            <div className="bg-white/20 p-2 rounded-full">
                <MapPin size={20} className="text-white" />
            </div>
            <div className="flex flex-col">
                <span className="text-xs text-blue-100">التوصيل إلى</span>
                <div className="flex items-center gap-1 font-bold cursor-pointer">
                    <span>الرياض، حي العليا</span>
                    <ChevronDown size={14} />
                </div>
            </div>
          </div>

          {/* Cart Icon (Top Left in RTL) */}
          <button 
            onClick={onGoToCart}
            className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center text-white border-2 border-white/30 relative active:scale-95 transition-transform"
          >
            <ShoppingCart size={20} />
            {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-secondary text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-primary">
                    {cartCount}
                </span>
            )}
          </button>
        </div>

        {/* Search Bar */}
        <div className="relative">
            <input 
                type="text" 
                placeholder="ابحث عن منتجات (مياه، أحجام...)" 
                className="w-full h-12 rounded-xl px-12 text-sm text-gray-800 placeholder-gray-400 shadow-lg focus:outline-none focus:ring-2 focus:ring-secondary/50"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
            <Search className="absolute right-4 top-3.5 text-gray-400" size={20} />
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`absolute left-2 top-2 h-8 w-8 rounded-lg flex items-center justify-center transition-colors ${activeFiltersCount > 0 ? 'bg-secondary text-white' : 'bg-gray-100 text-gray-600'}`}
            >
                <SlidersHorizontal size={16} />
                {activeFiltersCount > 0 && (
                    <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white"></span>
                )}
            </button>
        </div>
      </div>

      {/* Banner Carousel */}
      <div className="mt-6 px-4">
        <div className="w-full h-40 bg-gradient-to-l from-secondary to-pink-600 rounded-2xl shadow-lg relative overflow-hidden flex items-center px-6">
            <div className="text-white z-10 w-2/3">
                <span className="bg-white/20 text-xs px-2 py-1 rounded mb-2 inline-block">عروض رمضان</span>
                <h2 className="text-2xl font-bold mb-1">خصم 20%</h2>
                <p className="text-sm opacity-90 mb-3">على جميع اشتراكات المياه الشهرية</p>
                <button className="bg-white text-secondary px-4 py-1.5 rounded-full text-xs font-bold shadow-sm">اشترك الآن</button>
            </div>
            <div className="absolute -left-10 -bottom-10 w-48 h-48 bg-white/10 rounded-full blur-2xl"></div>
            <img 
                src="https://picsum.photos/200/200" 
                alt="Banner" 
                className="absolute left-4 top-4 w-32 h-32 object-contain drop-shadow-2xl rotate-12"
            />
        </div>
      </div>

      {/* Quick Filters */}
      <div className="mt-8 px-4">
        <h3 className="font-bold text-lg mb-3 text-gray-800">التصنيفات السريعة</h3>
        <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
            {[
                { id: 'all', label: 'الكل' },
                { id: 'best-sellers', label: 'الأكثر مبيعاً' },
                { id: 'low-sodium', label: 'صوديوم منخفض' },
                { id: 'donations', label: 'تبرعات المساجد' },
            ].map((cat) => (
                <button
                    key={cat.id}
                    onClick={() => setActiveQuickFilter(cat.id)}
                    className={`whitespace-nowrap px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                        activeQuickFilter === cat.id 
                        ? 'bg-primary text-white shadow-md' 
                        : 'bg-white text-gray-600 border border-gray-200'
                    }`}
                >
                    {cat.label}
                </button>
            ))}
        </div>
      </div>

      {/* Product Grid */}
      <div className="mt-6 px-4">
        <div className="flex justify-between items-end mb-4">
            <h3 className="font-bold text-lg text-gray-800">المنتجات ({filteredProducts.length})</h3>
            <div className="flex items-center gap-1 text-xs text-gray-500">
                <ArrowUpDown size={12} />
                <span>
                    {sortOption === 'price_asc' ? 'الأقل سعراً' : sortOption === 'price_desc' ? 'الأعلى سعراً' : 'المقترح'}
                </span>
            </div>
        </div>

        {filteredProducts.length > 0 ? (
             <div className="grid grid-cols-2 gap-4">
                {filteredProducts.map((product) => (
