};

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Search, MapPin, Navigation, X } from 'lucide-react';

interface LocationPickerProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (location: string) => void;
  initialLocation?: string;
}

