import React, { useState } from 'react';
import { CartProvider } from './store/CartContext';
import { AuthProvider, useAuth } from './store/AuthContext';
import { Home } from './pages/Home';
import { Checkout } from './pages/Checkout';
import { Profile } from './pages/Profile';
import { Promotions } from './pages/Promotions';
import { Subscriptions } from './pages/Subscriptions';
import { Brands } from './pages/Brands';
import { BrandDetails } from './pages/BrandDetails';
import { ProductDetails } from './pages/ProductDetails';
import { BottomNav } from './components/BottomNav';
import { Tab, Product, BrandInfo } from './types';
import { Loader2 } from 'lucide-react';

const AppContent: React.FC = () => {
  const { isLoading } = useAuth();
  const [currentTab, setCurrentTab] = useState<Tab>(Tab.HOME);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedBrand, setSelectedBrand] = useState<BrandInfo | null>(null);

  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-white text-primary">
        <Loader2 className="animate-spin" size={48} />
      </div>
    );
  }

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
  };

  const handleBrandClick = (brand: BrandInfo) => {
    setSelectedBrand(brand);
  };

  // If a product is selected, show details overlay/screen
  if (selectedProduct) {
      return (
        <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
             <ProductDetails product={selectedProduct} onBack={() => setSelectedProduct(null)} />
        </div>
      );
  }

  // If a brand is selected, show brand details overlay
  if (selectedBrand) {
      return (
          <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
              <BrandDetails 
                brand={selectedBrand} 
                onBack={() => setSelectedBrand(null)} 
                onProductClick={handleProductClick}
              />
          </div>
      );
  }

  const renderContent = () => {
    switch (currentTab) {
      case Tab.HOME:
        return <Home onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.BRANDS:
        return <Brands onBrandClick={handleBrandClick} onGoToCart={() => setCurrentTab(Tab.CART)} />;
      case Tab.PROMOTIONS:
        return <Promotions onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.SUBSCRIPTIONS:
        return <Subscriptions onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.CART:
        return <Checkout />;
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Home onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
      <main className="h-full overflow-y-auto no-scrollbar">
          {renderContent()}
      </main>
      <BottomNav currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <CartProvider>
        <AppContent />
      </CartProvider>
    </AuthProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { CartProvider } from './store/CartContext';
import { AuthProvider, useAuth } from './store/AuthContext';
import { Home } from './pages/Home';
import { Checkout } from './pages/Checkout';
import { Profile } from './pages/Profile';
import { Promotions } from './pages/Promotions';
import { Subscriptions } from './pages/Subscriptions';
import { Brands } from './pages/Brands';
import { BrandDetails } from './pages/BrandDetails';
import { ProductDetails } from './pages/ProductDetails';
import { BottomNav } from './components/BottomNav';
import { Tab, Product, BrandInfo } from './types';
import { Loader2 } from 'lucide-react';

const AppContent: React.FC = () => {
  const { isLoading } = useAuth();
  const [currentTab, setCurrentTab] = useState<Tab>(Tab.HOME);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedBrand, setSelectedBrand] = useState<BrandInfo | null>(null);

  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-white text-primary">
        <Loader2 className="animate-spin" size={48} />
      </div>
    );
  }

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
  };

  const handleBrandClick = (brand: BrandInfo) => {
    setSelectedBrand(brand);
  };

  const handleGoToCart = () => {
    setSelectedBrand(null);
    setSelectedProduct(null);
    setCurrentTab(Tab.CART);
  };

  // If a product is selected, show details overlay/screen
  if (selectedProduct) {
      return (
        <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
             <ProductDetails product={selectedProduct} onBack={() => setSelectedProduct(null)} />
        </div>
      );
  }

  // If a brand is selected, show brand details overlay
  if (selectedBrand) {
      return (
          <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
              <BrandDetails 
                brand={selectedBrand} 
                onBack={() => setSelectedBrand(null)} 
                onProductClick={handleProductClick}
                onGoToCart={handleGoToCart}
              />
          </div>
      );
  }

  const renderContent = () => {
    switch (currentTab) {
      case Tab.HOME:
        return <Home onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.BRANDS:
        return <Brands onBrandClick={handleBrandClick} onGoToCart={() => setCurrentTab(Tab.CART)} />;
      case Tab.PROMOTIONS:
        return <Promotions onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.SUBSCRIPTIONS:
        return <Subscriptions onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.CART:
        return <Checkout />;
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Home onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
      <main className="h-full overflow-y-auto no-scrollbar">
          {renderContent()}
      </main>
      <BottomNav currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <CartProvider>
        <AppContent />
      </CartProvider>
    </AuthProvider>
  );
};

export default App;

