import React, { useState } from 'react';
import { CartProvider } from './store/CartContext';
import { AuthProvider, useAuth } from './store/AuthContext';
import { Home } from './pages/Home';
import { Checkout } from './pages/Checkout';
import { Profile } from './pages/Profile';
import { Promotions } from './pages/Promotions';
import { Community } from './pages/Community';
import { Subscriptions } from './pages/Subscriptions';
import { Brands } from './pages/Brands';
import { BrandDetails } from './pages/BrandDetails';
import { ProductDetails } from './pages/ProductDetails';
import { BottomNav } from './components/BottomNav';
import { Tab, Product, BrandInfo } from './types';
import { Loader2 } from 'lucide-react';

const AppContent: React.FC = () => {
  const { isLoading } = useAuth();
  const [currentTab, setCurrentTab] = useState<Tab>(Tab.HOME);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedBrand, setSelectedBrand] = useState<BrandInfo | null>(null);

  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-white text-primary">
        <Loader2 className="animate-spin" size={48} />
      </div>
    );
  }

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
  };

  const handleBrandClick = (brand: BrandInfo) => {
    setSelectedBrand(brand);
  };

  const handleGoToCart = () => {
    setSelectedBrand(null);
    setSelectedProduct(null);
    setCurrentTab(Tab.CART);
  };

  // If a product is selected, show details overlay/screen
  if (selectedProduct) {
      return (
        <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
             <ProductDetails product={selectedProduct} onBack={() => setSelectedProduct(null)} />
        </div>
      );
  }

  // If a brand is selected, show brand details overlay
  if (selectedBrand) {
      return (
          <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
              <BrandDetails 
                brand={selectedBrand} 
                onBack={() => setSelectedBrand(null)} 
                onProductClick={handleProductClick}
                onGoToCart={handleGoToCart}
              />
          </div>
      );
  }

  const renderContent = () => {
    switch (currentTab) {
      case Tab.HOME:
        return <Home onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.BRANDS:
        return <Brands onBrandClick={handleBrandClick} onGoToCart={() => setCurrentTab(Tab.CART)} />;
      case Tab.COMMUNITY:
        return <Community onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.SUBSCRIPTIONS:
        return <Subscriptions onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.CART:
        return <Checkout />;
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Home onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
      <main className="h-full overflow-y-auto no-scrollbar">
          {renderContent()}
      </main>
      <BottomNav currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <CartProvider>
        <AppContent />
      </CartProvider>
    </AuthProvider>
  );
};

export default App;

import React from 'react';
import { Product } from '../types';
import { useCart } from '../store/CartContext';
import { Plus, Minus, RefreshCw, Star } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  onProductClick?: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product, onProductClick }) => {
  const { items, addToCart, updateQuantity, toggleSubscription } = useCart();
  const cartItem = items.find((i) => i.id === product.id);
  const quantity = cartItem?.quantity || 0;
  const isSubscribed = cartItem?.isSubscribed || false;

  const handleCardClick = () => {
    if (onProductClick) {
        onProductClick(product);
    }
  };

  const handleAdd = (e: React.MouseEvent) => {
    e.stopPropagation();
    addToCart(product);
  };

  const handleIncrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    updateQuantity(product.id, 1);
  };

  const handleDecrement = (e: React.MouseEvent) => {
    e.stopPropagation();
    updateQuantity(product.id, -1);
  };

  const handleSubscribeToggle = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (quantity > 0) {
      toggleSubscription(product.id);
    } else {
        // Auto add if toggling subscription on empty item
        addToCart(product);
        setTimeout(() => toggleSubscription(product.id), 0);
    }
  };

  const formatReviews = (count: number) => {
    if (count >= 1000) return `${(count / 1000).toFixed(1)}k`;
    return count;
  };

  return (
    <div 
        onClick={handleCardClick}
        className={`bg-white rounded-xl shadow-sm overflow-hidden flex flex-col h-full relative group cursor-pointer active:scale-[0.99] transition-all duration-300 ${
            isSubscribed 
            ? 'border-2 border-secondary/60 shadow-lg shadow-secondary/10 bg-pink-50/10' 
            : 'border border-gray-100 hover:shadow-md'
        }`}
    >
      {/* Badges */}
      <div className="absolute top-2 right-2 flex flex-col gap-1 z-10">
        {product.sodiumLevel < 15 && (
            <span className="bg-green-100 text-green-700 text-[10px] px-2 py-1 rounded-full font-bold">
            صوديوم منخفض
            </span>
        )}
        {isSubscribed && (
            <span className="bg-secondary text-white text-[10px] px-2 py-1 rounded-full font-bold shadow-md animate-pulse flex items-center gap-1">
                <RefreshCw size={8} className="animate-spin-slow" />
                مشترك حالياً
            </span>
        )}
      </div>

      {/* Image Area */}
      <div className="h-40 relative flex items-center justify-center p-4 transition-colors">
        <div className={`absolute inset-0 ${isSubscribed ? 'bg-secondary/5' : 'bg-gray-50'}`}></div>
        <img
          src={product.imageUrl}
          alt={product.nameEn}
          className="max-h-full max-w-full object-contain mix-blend-multiply relative z-10"
        />
      </div>

      {/* Content Area */}
      <div className="p-3 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-1">
          <div>
            <h3 className="font-bold text-gray-800 text-base leading-tight">{product.nameAr}</h3>
            <p className="text-gray-400 text-xs font-sans mt-0.5">{product.nameEn}</p>
          </div>
        </div>

        {/* Rating */}
        <div className="flex items-center gap-1 mb-2">
             <Star size={12} className="fill-orange-400 text-orange-400" />
             <span className="text-xs font-bold text-gray-700">{product.rating}</span>
             <span className="text-[10px] text-gray-400">({formatReviews(product.reviews)})</span>
        </div>

        <div className="flex items-center gap-2 text-xs text-gray-500 mb-2">
            <span className="bg-gray-100 px-1.5 py-0.5 rounded text-gray-600">{product.size}</span>
            <span>pH {product.phLevel}</span>
        </div>

        <div className="mt-auto">
            <div className="flex items-center justify-between mb-3">
                <div className="flex flex-col">
                    <span className={`font-bold text-lg transition-colors ${isSubscribed ? 'text-secondary' : 'text-primary'}`}>
                        {isSubscribed ? (product.price * 0.9).toFixed(2) : product.price.toFixed(2)}
                        <span className="text-xs text-gray-500 mr-1 font-normal">ر.س</span>
                    </span>
                     {isSubscribed && <span className="text-[10px] text-gray-400 line-through">{product.price.toFixed(2)}</span>}
                </div>
            </div>

            {/* Quick Actions */}
            <div className="flex items-center justify-between gap-2">
                {quantity === 0 ? (
                    <button
                        onClick={handleAdd}
                        className="w-full bg-primary text-white py-2 rounded-lg font-bold text-sm shadow-md active:scale-95 transition-transform flex items-center justify-center gap-2"
                    >
                        <Plus size={16} />
                        <span>أضف للسلة</span>
                    </button>
                ) : (
                    <div className="flex items-center bg-gray-100 rounded-lg w-full justify-between p-1">
                        <button onClick={handleIncrement} className="w-8 h-8 bg-white rounded shadow-sm text-primary flex items-center justify-center active:scale-95">
                            <Plus size={16} />
                        </button>
                        <span className="font-bold text-gray-800 text-sm mx-2">{quantity}</span>
                        <button onClick={handleDecrement} className="w-8 h-8 bg-white rounded shadow-sm text-gray-500 flex items-center justify-center active:scale-95">
                            <Minus size={16} />
                        </button>
                    </div>
                )}
            </div>

            {/* Subscription Toggle */}
            {product.isSubscriptionAvailable && (
                 <button
                    onClick={handleSubscribeToggle}
                    className={`w-full mt-2 py-1.5 px-2 rounded border border-dashed flex items-center justify-center gap-1.5 text-xs transition-colors ${
                        isSubscribed
                        ? 'border-secondary text-secondary bg-pink-50 font-bold'
                        : 'border-gray-300 text-gray-500 hover:bg-gray-50'
                    }`}
                 >
                    <RefreshCw size={12} className={isSubscribed ? 'animate-spin-slow' : ''} />
                    <span>{isSubscribed ? 'إلغاء الاشتراك' : 'اشترك ووفر 10%'}</span>
                 </button>
            )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Product } from '../types';
import { useCart } from '../store/CartContext';
import { ChevronRight, Share2, Heart, Plus, Minus, RefreshCw, Droplets, FlaskConical, Scaling, Tag, Check, Star } from 'lucide-react';

interface ProductDetailsProps {
  product: Product;
  onBack: () => void;
}

export const ProductDetails: React.FC<ProductDetailsProps> = ({ product, onBack }) => {
  const { items, addToCart, updateQuantity, toggleSubscription } = useCart();
  const cartItem = items.find((i) => i.id === product.id);
  const quantity = cartItem?.quantity || 0;
  const isSubscribed = cartItem?.isSubscribed || false;

  const handleAdd = () => addToCart(product);
  const handleIncrement = () => updateQuantity(product.id, 1);
  const handleDecrement = () => updateQuantity(product.id, -1);

  const handleSubscribeToggle = () => {
    if (quantity > 0) {
      toggleSubscription(product.id);
    } else {
        addToCart(product);
        setTimeout(() => toggleSubscription(product.id), 0);
