import React, { useState } from 'react';
import { CartProvider } from './store/CartContext';
import { AuthProvider, useAuth } from './store/AuthContext';
import { Home } from './pages/Home';
import { Checkout } from './pages/Checkout';
import { Profile } from './pages/Profile';
import { Promotions } from './pages/Promotions';
import { Community } from './pages/Community';
import { Subscriptions } from './pages/Subscriptions';
import { Brands } from './pages/Brands';
import { BrandDetails } from './pages/BrandDetails';
import { ProductDetails } from './pages/ProductDetails';
import { BottomNav } from './components/BottomNav';
import { Tab, Product, BrandInfo } from './types';
import { Loader2 } from 'lucide-react';

const AppContent: React.FC = () => {
  const { isLoading } = useAuth();
  const [currentTab, setCurrentTab] = useState<Tab>(Tab.HOME);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedBrand, setSelectedBrand] = useState<BrandInfo | null>(null);

  if (isLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-white text-primary">
        <Loader2 className="animate-spin" size={48} />
      </div>
    );
  }

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
  };

  const handleBrandClick = (brand: BrandInfo) => {
    setSelectedBrand(brand);
  };

  const handleGoToCart = () => {
    setSelectedBrand(null);
    setSelectedProduct(null);
    setCurrentTab(Tab.CART);
  };

  // If a product is selected, show details overlay/screen
  if (selectedProduct) {
      return (
        <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
             <ProductDetails product={selectedProduct} onBack={() => setSelectedProduct(null)} />
        </div>
      );
  }

  // If a brand is selected, show brand details overlay
  if (selectedBrand) {
      return (
          <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
              <BrandDetails 
                brand={selectedBrand} 
                onBack={() => setSelectedBrand(null)} 
                onProductClick={handleProductClick}
                onGoToCart={handleGoToCart}
              />
          </div>
      );
  }

  const renderContent = () => {
    switch (currentTab) {
      case Tab.HOME:
        return <Home 
          onGoToCart={() => setCurrentTab(Tab.CART)} 
          onGoToProfile={() => setCurrentTab(Tab.PROFILE)}
          onProductClick={handleProductClick} 
        />;
      case Tab.BRANDS:
        return <Brands onBrandClick={handleBrandClick} onGoToCart={() => setCurrentTab(Tab.CART)} />;
      case Tab.COMMUNITY:
        return <Community onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.SUBSCRIPTIONS:
        return <Subscriptions onGoToCart={() => setCurrentTab(Tab.CART)} onProductClick={handleProductClick} />;
      case Tab.CART:
        return <Checkout />;
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Home 
          onGoToCart={() => setCurrentTab(Tab.CART)} 
          onGoToProfile={() => setCurrentTab(Tab.PROFILE)}
          onProductClick={handleProductClick} 
        />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-100 min-h-screen relative shadow-2xl overflow-hidden font-sans">
      <main className="h-full overflow-y-auto no-scrollbar">
          {renderContent()}
      </main>
      <BottomNav currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <CartProvider>
        <AppContent />
      </CartProvider>
    </AuthProvider>
  );
};

export default App;

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  sendOtp: (phone: string) => Promise<void>;
  verifyOtp: (phone: string, code: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => void;
  error: string | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Check local storage
    const stored = localStorage.getItem('wadi_user');
    if (stored) {
      setUser(JSON.parse(stored));
    }
    setIsLoading(false);
  }, []);

  const sendOtp = async (phone: string) => {
    setIsLoading(true);
    setError(null);
    // Simulate API call to send SMS
    return new Promise<void>((resolve) => {
        setTimeout(() => {
            setIsLoading(false);
            resolve();
        }, 1500);
    });
  };

  const verifyOtp = async (phone: string, code: string) => {
    setIsLoading(true);
    setError(null);
    return new Promise<void>((resolve, reject) => {
        setTimeout(() => {
            if (code === '1234') { // Mock OTP
                const u: User = {
                    id: `u_${phone}`,
                    name: 'عميل وادي', // Default name, could ask for it later
                    email: `${phone}@wadi.com`,
                    phone: phone,
                    avatarUrl: `https://ui-avatars.com/api/?name=${phone}&background=random`,
                };
                setUser(u);
                localStorage.setItem('wadi_user', JSON.stringify(u));
                setIsLoading(false);
                resolve();
            } else {
                setError('رمز التحقق غير صحيح');
                setIsLoading(false);
                reject();
            }
        }, 1500);
    });
  };

  const register = async (name: string, email: string, pass: string) => {
    setIsLoading(true);
    setError(null);
    return new Promise<void>((resolve) => {
        setTimeout(() => {
            const u: User = {
                id: `u_${Date.now()}`,
                name: name,
                email: email,
                avatarUrl: `https://ui-avatars.com/api/?name=${name}&background=random`,
            };
            setUser(u);
            localStorage.setItem('wadi_user', JSON.stringify(u));
            setIsLoading(false);
            resolve();
        }, 1500);
    });
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('wadi_user');
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, sendOtp, verifyOtp, register, logout, error }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

