import React, { createContext, useContext, useState, useEffect, ReactNode, useRef } from 'react';
import { User } from '../types';
import { auth } from '../firebase';
import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult, 
  onAuthStateChanged, 
  signOut,
  createUserWithEmailAndPassword,
  updateProfile,
  User as FirebaseUser
} from 'firebase/auth';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  sendOtp: (phone: string) => Promise<void>;
  verifyOtp: (phone: string, code: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => void;
  error: string | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Store the confirmation result from Firebase Phone Auth
  const confirmationResultRef = useRef<ConfirmationResult | null>(null);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        mapFirebaseUserToLocal(firebaseUser);
      } else {
        setUser(null);
      }
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const mapFirebaseUserToLocal = (firebaseUser: FirebaseUser) => {
    const u: User = {
      id: firebaseUser.uid,
      name: firebaseUser.displayName || 'عميل وادي',
      email: firebaseUser.email || `${firebaseUser.phoneNumber}@wadi.com`,
      phone: firebaseUser.phoneNumber || '',
      avatarUrl: firebaseUser.photoURL || `https://ui-avatars.com/api/?name=${firebaseUser.phoneNumber || 'User'}&background=random`,
    };
    setUser(u);
  };

  const setupRecaptcha = () => {
    if (!(window as any).recaptchaVerifier) {
      (window as any).recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-container', {
        'size': 'invisible',
        'callback': () => {
          // reCAPTCHA solved, allow signInWithPhoneNumber.
        }
      });
    }
  };

  const sendOtp = async (phone: string) => {
    setIsLoading(true);
    setError(null);
    try {
      setupRecaptcha();
      const appVerifier = (window as any).recaptchaVerifier;
      // Format phone number to E.164 format (assuming SA +966)
      const formattedPhone = phone.startsWith('+') ? phone : `+966${phone.startsWith('0') ? phone.slice(1) : phone}`;

      const confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, appVerifier);
      confirmationResultRef.current = confirmationResult;
      setIsLoading(false);
    } catch (err: any) {
      console.error('Error sending OTP:', err);
      setIsLoading(false);

      let msg = 'حدث خطأ أثناء إرسال الرمز، يرجى المحاولة مرة أخرى';
      if (err.code === 'auth/invalid-phone-number') {
        msg = 'رقم الجوال غير صحيح';
      } else if (err.code === 'auth/too-many-requests') {
        msg = 'تم تجاوز الحد المسموح من المحاولات، يرجى المحاولة لاحقاً';
      } else if (err.code === 'auth/quota-exceeded') {
        msg = 'نأسف، حدث خطأ في خدمة الرسائل. يرجى المحاولة لاحقاً';
      } else if (err.code === 'auth/network-request-failed') {
        msg = 'تأكد من اتصالك بالإنترنت';
      } else if (err.message && err.message.includes('reCAPTCHA')) {
          msg = 'فشل التحقق من الأمان (reCAPTCHA)، يرجى تحديث الصفحة';
      }

      setError(msg);

      // Reset recaptcha
      if ((window as any).recaptchaVerifier) {
          try {
            (window as any).recaptchaVerifier.clear();
          } catch(e) { /* ignore cleanup errors */ }
          (window as any).recaptchaVerifier = null;
      }
    }
  };

  const verifyOtp = async (phone: string, code: string) => {
    setIsLoading(true);
    setError(null);
    try {
      if (!confirmationResultRef.current) {
        throw new Error('No verification session found');
      }
      await confirmationResultRef.current.confirm(code);
      // User is automatically set by onAuthStateChanged
    } catch (err: any) {
      console.error('Error verifying OTP:', err);
      setIsLoading(false);

      let msg = 'فشل التحقق، يرجى المحاولة مرة أخرى';
      if (err.code === 'auth/invalid-verification-code') {
        msg = 'رمز التحقق غير صحيح';
      } else if (err.code === 'auth/code-expired') {
        msg = 'انتهت صلاحية الرمز، يرجى طلب رمز جديد';
      } else if (err.code === 'auth/session-expired') {
         msg = 'انتهت جلسة التحقق، يرجى إعادة المحاولة';
      } else if (err.code === 'auth/network-request-failed') {
        msg = 'تأكد من اتصالك بالإنترنت';
      }

      setError(msg);
      throw err; // Re-throw to allow component to handle if needed
    }
  };

  const register = async (name: string, email: string, pass: string) => {
    setIsLoading(true);
    setError(null);
    try {
        const userCredential = await createUserWithEmailAndPassword(auth, email, pass);
        await updateProfile(userCredential.user, {
            displayName: name,
            photoURL: `https://ui-avatars.com/api/?name=${name}&background=random`
        });
        // User is automatically set by onAuthStateChanged
    } catch (err: any) {
        console.error(err);
        setIsLoading(false);
        if (err.code === 'auth/email-already-in-use') {
            setError('البريد الإلكتروني مستخدم بالفعل');
        } else if (err.code === 'auth/weak-password') {
            setError('كلمة المرور ضعيفة جداً');
        } else {
            setError('حدث خطأ أثناء إنشاء الحساب');
        }
    }
  };

  const logout = async () => {
    try {
      await signOut(auth);
      setUser(null);
      // Reset local state if needed
      confirmationResultRef.current = null;
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, sendOtp, verifyOtp, register, logout, error }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

import React, { useState } from 'react';
import { useAuth } from '../store/AuthContext';
import { Loader2, ArrowRight, Smartphone, ShieldCheck } from 'lucide-react';

export const Login: React.FC = () => {
  const { sendOtp, verifyOtp, isLoading, error } = useAuth();
  const [step, setStep] = useState<'phone' | 'otp'>('phone');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let val = e.target.value.replace(/\D/g, ''); // Remove non-digits
    if (val.startsWith('0')) {
        val = val.substring(1); // Remove leading zero
    }
    if (val.length > 9) {
        val = val.slice(0, 9); // Limit to 9 digits (Saudi mobile length without 0)
    }
    setPhone(val);
  };

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 9) return; // Strict 9 digits check
    await sendOtp(phone);
    setStep('otp');
  };

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
        await verifyOtp(phone, otp);
        // AuthContext updates user, parent component will re-render
    } catch (err) {
        // Error handled in context
    }
  };

  return (
    <div className="flex flex-col items-center justify-center p-6 bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[400px]">
      <div className="mb-6 text-center">
        <div className="w-16 h-16 bg-primary/10 rounded-full flex items-center justify-center mx-auto mb-4 text-primary">
            {step === 'phone' ? <Smartphone size={32} /> : <ShieldCheck size={32} />}
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">
            {step === 'phone' ? 'تسجيل الدخول' : 'تأكيد الرقم'}
        </h2>
        <p className="text-gray-500 text-sm">
            {step === 'phone' 
                ? 'أدخل رقم جوالك للمتابعة وإتمام الطلب' 
                : `تم إرسال رمز التحقق إلى 966${phone}+`
            }
        </p>
      </div>

      {error && (
        <div className="w-full bg-red-50 text-red-600 p-3 rounded-lg text-sm text-center font-medium mb-4">
            {error}
        </div>
      )}

      {step === 'phone' ? (
        <form onSubmit={handleSendOtp} className="w-full space-y-4">
            <div className="space-y-1">
                <label className="text-sm font-medium text-gray-700">رقم الجوال</label>
                <div className="relative text-left" dir="ltr">
                    <input 
                        type="tel" 
                        value={phone}
                        onChange={handlePhoneChange}
                        className="w-full h-12 px-4 pl-14 rounded-xl border border-gray-200 focus:border-primary focus:ring-2 focus:ring-primary/20 outline-none transition-all text-lg tracking-widest font-mono"
                        placeholder="5XXXXXXXX"
                        autoFocus
                        required
                    />
                    <div className="absolute left-3 top-3.5 text-gray-500 font-bold border-r pr-2 border-gray-200 select-none bg-white">
                        +966
                    </div>
                </div>
                <p className="text-xs text-gray-400 text-right mt-1">ابدأ الرقم بـ 5 مباشرة (بدون 0)</p>
            </div>

            <button 
                type="submit" 
                disabled={isLoading || phone.length !== 9}
                className="w-full h-12 bg-primary text-white rounded-xl font-bold text-lg shadow-lg shadow-primary/30 flex items-center justify-center gap-2 active:scale-[0.98] transition-all disabled:opacity-70 disabled:cursor-not-allowed"
            >
                {isLoading ? <Loader2 className="animate-spin" /> : 'أرسل الرمز'}
            </button>
        </form>
      ) : (
        <form onSubmit={handleVerify} className="w-full space-y-4">
             <div className="space-y-1">
                <label className="text-sm font-medium text-gray-700">رمز التحقق (OTP)</label>
                <div className="relative">
                    <input 
                        type="text" 
                        value={otp}
                        onChange={(e) => setOtp(e.target.value)}
                        className="w-full h-12 px-4 rounded-xl border border-gray-200 focus:border-primary focus:ring-2 focus:ring-primary/20 outline-none transition-all text-center text-2xl tracking-[1em] font-mono"
                        placeholder="----"
                        maxLength={6}
                        autoFocus
                        required
                    />
                </div>
            </div>

            <button 
                type="submit" 
                disabled={isLoading || otp.length < 6}
                className="w-full h-12 bg-primary text-white rounded-xl font-bold text-lg shadow-lg shadow-primary/30 flex items-center justify-center gap-2 active:scale-[0.98] transition-all disabled:opacity-70 disabled:cursor-not-allowed"
            >
                {isLoading ? <Loader2 className="animate-spin" /> : 'تحقق'}
            </button>

            <button 
                type="button"
                onClick={() => setStep('phone')}
                className="w-full text-gray-500 text-sm py-2 flex items-center justify-center gap-1 hover:text-gray-700"
            >
                <ArrowRight size={14} />
                تغيير رقم الجوال
            </button>
        </form>
      )}
    </div>
  );
};

